void adaptive_sort(std::vector<int>& arr) {
    const size_t n = arr.size();
    if (n < 2) return;

    // One-pass check for initial sorted run
    auto it = std::is_sorted_until(arr.begin(), arr.end());
    if (it == arr.end()) return;

    // Hint-based check for reverse sorted
    if (arr.front() >= arr.back()) {
        if (std::is_sorted(arr.rbegin(), arr.rend())) {
            std::reverse(arr.begin(), arr.end());
            return;
        }
    }

    // Optimization: handle two sorted runs (e.g., [sorted] + [sorted])
    const size_t prefix_len = static_cast<size_t>(it - arr.begin());
    if (prefix_len > n / 2 || (n - prefix_len) < 64) {
        if (std::is_sorted(it, arr.end())) {
            std::inplace_merge(arr.begin(), it, arr.end());
            return;
        }
    }

    // Fallback for random data
    std::sort(arr.begin(), arr.end());
}

